// Script Continued Below
(function runMailScript(current, template, email, email_action, event) {

	var newSubject;
	if (current.u_status == 'In progress'){
		newSubject = gs.getMessage("{0}, Request: {1}", [current.u_ou_parent.office_name, current.getDisplayValue('u_request_type')]);
	} else {
		newSubject = gs.getMessage("{0}, Response for Request: {1}", [current.u_ou_parent.office_name, current.getDisplayValue('u_request_type')]);
	}

	email.setSubject(newSubject);

	template.print(gs.getMessage("Hi,"));
	template.print("<br/><br/>");
	if (current.u_status == 'In progress'){
		template.print(gs.getMessage("<b>{0}</b> has requested <b>{1}</b>  for <b>{2}</b>", 
									[current.getDisplayValue('u_requested_by'), 
									current.getDisplayValue('u_request_type'), 
									current.u_ou_parent.office_name]));
	} else{
		template.print(gs.getMessage("<b>{0}</b> has <b>{1}</b> the <b>{2}</b> for <b>{3}</b>", 
									[current.getDisplayValue('u_requested_by'), 
									current.u_response,
									current.getDisplayValue('u_request_type'), 
									current.u_ou_parent.office_name]));
	}
	template.print("<br/><br/>");
	template.print("<br/><br/>");
	template.print(gs.getMessage("Please navigate to the Modern Portal to review your requests or follow this <a href='{0}'>link</a>", 
								'discovertaskerportal?id=discover_simple_processing_form&dtr_sys_id=${sys_id}&dtr_view=OU_ResponseTop&dtr_table=x_153465_discovert_tasker_requests&dtr_ref=u_ou_parent'));
	template.print("<br/><br/>");



	template.print(gs.getMessage("<b>Full Request Comments</b>"));
	template.print("<br/><br/>");
	template.print(current.u_request_comments);

gs.info('RJ - Testing, is the email getting gnerated');

})(current, template, email, email_action, event);
